import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Dashboard = ({ user }) => {
  const navigate = useNavigate();

  const handleLogout = async () => {
    try {
      await fetch('/api/auth/logout', {
        method: 'POST',
        credentials: 'include'
      });
      navigate('/login');
    } catch (error) {
      console.error('Logout error:', error);
    }
  };

  return (
    <div style={{ padding: '2rem', minHeight: '100vh' }}>
      <header style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        marginBottom: '2rem',
        borderBottom: '1px solid #eee',
        paddingBottom: '1rem'
      }}>
        <h1>Event Management System Dashboard</h1>
        <div>
          <span>Welcome, {user.username} ({user.role}) | </span>
          <button 
            onClick={handleLogout}
            style={{
              marginLeft: '1rem',
              padding: '0.5rem 1rem',
              backgroundColor: '#dc3545',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            Logout
          </button>
        </div>
      </header>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1.5rem' }}>
        {/* Maintenance Module (Admin only) */}
        {user.role === 'admin' && (
          <div style={{
            border: '1px solid #ddd',
            borderRadius: '8px',
            padding: '1.5rem',
            backgroundColor: '#f8f9fa'
          }}>
            <h2>Maintenance</h2>
            <ul style={{ listStyle: 'none', padding: 0 }}>
              <li style={{ marginBottom: '0.5rem' }}>
                <Link to="/maintenance/membership" style={{ textDecoration: 'none', color: '#007bff' }}>
                  Add/Update Membership
                </Link>
              </li>
              <li style={{ marginBottom: '0.5rem' }}>
                <Link to="/maintenance/members" style={{ textDecoration: 'none', color: '#007bff' }}>
                  Member List
                </Link>
              </li>
            </ul>
          </div>
        )}

        {/* Reports Module (All users) */}
        <div style={{
          border: '1px solid #ddd',
          borderRadius: '8px',
          padding: '1.5rem',
          backgroundColor: '#f8f9fa'
        }}>
          <h2>Reports</h2>
          <ul style={{ listStyle: 'none', padding: 0 }}>
            <li style={{ marginBottom: '0.5rem' }}>
              <Link to="/reports/membership" style={{ textDecoration: 'none', color: '#007bff' }}>
                Membership Report
              </Link>
            </li>
            <li style={{ marginBottom: '0.5rem' }}>
              <Link to="/reports/transactions" style={{ textDecoration: 'none', color: '#007bff' }}>
                Transaction Report
              </Link>
            </li>
          </ul>
        </div>

        {/* Transactions Module (All users) */}
        <div style={{
          border: '1px solid #ddd',
          borderRadius: '8px',
          padding: '1.5rem',
          backgroundColor: '#f8f9fa'
        }}>
          <h2>Transactions</h2>
          <ul style={{ listStyle: 'none', padding: 0 }}>
            <li style={{ marginBottom: '0.5rem' }}>
              <Link to="/transactions/register" style={{ textDecoration: 'none', color: '#007bff' }}>
                Event Registration
              </Link>
            </li>
            <li style={{ marginBottom: '0.5rem' }}>
              <Link to="/transactions/payment" style={{ textDecoration: 'none', color: '#007bff' }}>
                Payment Processing
              </Link>
            </li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
